"use strict";(self.webpackChunkwave_lang=self.webpackChunkwave_lang||[]).push([[320],{5666:(e,n,t)=>{t.r(n),t.d(n,{assets:()=>l,contentTitle:()=>o,default:()=>c,frontMatter:()=>r,metadata:()=>s,toc:()=>u});const s=JSON.parse('{"id":"intro/intro","title":"Introduction","description":"Philosophie et objectifs de Wave","source":"@site/i18n/fr/docusaurus-plugin-content-docs/current/intro/intro.md","sourceDirName":"intro","slug":"/intro/","permalink":"/fr/docs/intro/","draft":false,"unlisted":false,"tags":[],"version":"current","sidebarPosition":0,"frontMatter":{"sidebar_position":0},"sidebar":"tutorialSidebar","next":{"title":"Installation","permalink":"/fr/docs/intro/installation"}}');var a=t(4848),i=t(8453);const r={sidebar_position:0},o="Introduction",l={},u=[{value:"Philosophie et objectifs de Wave",id:"philosophie-et-objectifs-de-wave",level:2},{value:"Caract\xe9ristiques et attributs majeurs de Wave",id:"caract\xe9ristiques-et-attributs-majeurs-de-wave",level:2},{value:"Feuille de route et plans de Wave",id:"feuille-de-route-et-plans-de-wave",level:2}];function d(e){const n={h1:"h1",h2:"h2",header:"header",p:"p",...(0,i.R)(),...e.components};return(0,a.jsxs)(a.Fragment,{children:[(0,a.jsx)(n.header,{children:(0,a.jsx)(n.h1,{id:"introduction",children:"Introduction"})}),"\n",(0,a.jsx)(n.h2,{id:"philosophie-et-objectifs-de-wave",children:"Philosophie et objectifs de Wave"}),"\n",(0,a.jsx)(n.p,{children:"Wave n'a pas pour objectif de simplement remplacer les langages de programmation bas niveau existants.\nIl s'agit plut\xf4t d'un langage con\xe7u pour maintenir le contr\xf4le et la performance des langages de bas niveau tout en les compl\xe9tant et les simplifiant, permettant de g\xe9rer diff\xe9rents domaines de d\xe9veloppement dans un langage et un \xe9cosyst\xe8me coh\xe9rents."}),"\n",(0,a.jsx)(n.p,{children:"Wave vise \xe0 s'\xe9carter de la m\xe9thode consistant \xe0 traiter des domaines tr\xe8s diff\xe9rents comme le d\xe9veloppement web, les syst\xe8mes d'exploitation, l'intelligence artificielle, la blockchain, le contr\xf4le mat\xe9riel, les compilateurs, les r\xe9seaux, et le cryptage, chacun avec un langage diff\xe9rent.\nL'objectif principal de Wave est de fournir une exp\xe9rience de d\xe9veloppement int\xe9gr\xe9e qui couvre naturellement de vastes domaines par un seul langage, un seul ensemble d'outils et une seule biblioth\xe8que standard."}),"\n",(0,a.jsx)(n.p,{children:"La philosophie de Wave repose sur la coexistence d'une puissante abstraction de haut niveau et d'un contr\xf4le pr\xe9cis de bas niveau.\nGr\xe2ce \xe0 la biblioth\xe8que standard, les t\xe2ches complexes peuvent \xeatre g\xe9r\xe9es de mani\xe8re intuitive, tout en permettant un acc\xe8s direct \xe0 la m\xe9moire, aux registres et aux ressources mat\xe9rielles si n\xe9cessaire.\nCela permet aux d\xe9veloppeurs de faire des choix adapt\xe9s \xe0 la situation sans compromettre la commodit\xe9 ni la performance."}),"\n",(0,a.jsx)(n.p,{children:"La biblioth\xe8que mat\xe9rielle de Wave est l'un des \xe9l\xe9ments de conception majeurs.\nElle est con\xe7ue pour \xeatre facilement utilisable m\xeame par les d\xe9veloppeurs n'ayant pas de connaissances avanc\xe9es en mat\xe9riel, tout en offrant la flexibilit\xe9 de contr\xf4ler directement via des interfaces de bas niveau lorsque cela est n\xe9cessaire.\nCette approche permet d'utiliser les fonctionnalit\xe9s mat\xe9rielles de mani\xe8re plus intuitive sans sacrifier la performance."}),"\n",(0,a.jsx)(n.p,{children:"Wave s'efforce de supprimer les barri\xe8res entre la programmation de haut niveau et de bas niveau, simplifiant l'exp\xe9rience de d\xe9veloppement dans un environnement de langage coh\xe9rent."}),"\n",(0,a.jsx)(n.h2,{id:"caract\xe9ristiques-et-attributs-majeurs-de-wave",children:"Caract\xe9ristiques et attributs majeurs de Wave"}),"\n",(0,a.jsx)(n.p,{children:"Wave a pour caract\xe9ristique majeure l'int\xe9gration de divers domaines de d\xe9veloppement dans une seule structure linguistique.\nAinsi, les d\xe9veloppeurs peuvent r\xe9soudre des probl\xe8mes dans divers domaines sans avoir \xe0 apprendre un nouveau langage pour chaque projet, se contentant de Wave."}),"\n",(0,a.jsx)(n.p,{children:"La puissante biblioth\xe8que standard est un \xe9l\xe9ment cl\xe9 qui soutient la productivit\xe9 de Wave.\nElle est con\xe7ue pour permettre l'expression de t\xe2ches complexes par un code concis, permettant ainsi aux d\xe9veloppeurs de se concentrer sur la r\xe9solution de probl\xe8mes plut\xf4t que sur des impl\xe9mentations r\xe9p\xe9titives."}),"\n",(0,a.jsx)(n.p,{children:"L'accessibilit\xe9 mat\xe9rielle est \xe9galement une caract\xe9ristique importante de Wave.\nWave est con\xe7u pour offrir une interface de haut niveau facile \xe0 manipuler pour le mat\xe9riel, tout en permettant une gestion directe de bas niveau si n\xe9cessaire.\nCela permet d'inclure aussi bien les d\xe9butants que les d\xe9veloppeurs syst\xe8me exp\xe9riment\xe9s."}),"\n",(0,a.jsx)(n.p,{children:"La performance est un \xe9l\xe9ment intransigeant dans la conception de Wave.\nBas\xe9 sur une structure de compilateur efficace et un mod\xe8le de m\xe9moire clair, il est con\xe7u pour fonctionner de mani\xe8re stable m\xeame dans des applications o\xf9 la performance est cruciale."}),"\n",(0,a.jsx)(n.p,{children:"Wave accorde une grande importance \xe0 la modularisation et \xe0 la r\xe9utilisabilit\xe9.\nIl favorise la s\xe9paration du code en unit\xe9s claires r\xe9utilisables, ce qui permet de g\xe9rer efficacement la complexit\xe9, m\xeame lorsque la taille du projet augmente."}),"\n",(0,a.jsx)(n.p,{children:"De plus, Wave vise \xe0 fournir des messages d'erreur clairs et intuitifs ainsi qu'un environnement de d\xe9bogage.\nCela permet aux d\xe9veloppeurs de localiser et r\xe9soudre rapidement la cause des probl\xe8mes, r\xe9duisant ainsi les essais et erreurs inutiles durant le processus d'apprentissage."}),"\n",(0,a.jsx)(n.h2,{id:"feuille-de-route-et-plans-de-wave",children:"Feuille de route et plans de Wave"}),"\n",(0,a.jsx)(n.p,{children:"Wave est con\xe7u sur la base d'un d\xe9veloppement par \xe9tapes.\nDans les \xe9tapes initiales, l'accent est mis sur la syntaxe de base du langage et ses fonctions fondamentales, avec l'intention d'\xe9largir progressivement vers des fonctionnalit\xe9s comme le pattern matching, la programmation asynchrone et les structures de donn\xe9es avanc\xe9es."}),"\n",(0,a.jsx)(n.p,{children:"La biblioth\xe8que standard est pr\xe9vue pour \xeatre continuellement \xe9largie en fonction des besoins des utilisateurs et des cas d'utilisation r\xe9els.\nAinsi, les d\xe9veloppeurs pourront de plus en plus r\xe9soudre des fonctionnalit\xe9s au niveau de la biblioth\xe8que."}),"\n",(0,a.jsx)(n.p,{children:"La biblioth\xe8que mat\xe9rielle est \xe9galement un \xe9l\xe9ment central de Wave et fait l'objet d'am\xe9liorations continues.\nNous pr\xe9voyons d'assurer une compatibilit\xe9 avec un plus grand nombre d'appareils et d'ajouter de nouvelles fonctions de contr\xf4le pour \xe9tendre la port\xe9e d'utilisation dans les environnements mat\xe9riels r\xe9els."}),"\n",(0,a.jsx)(n.p,{children:"Wave accorde une grande importance aux retours de la communaut\xe9.\nNous pr\xe9voyons de recueillir activement les opinions des utilisateurs via des forums et divers canaux de feedback, et de les int\xe9grer dans le d\xe9veloppement du langage et des outils."}),"\n",(0,a.jsx)(n.p,{children:"La documentation et les supports \xe9ducatifs constituent \xe9galement l'une des orientations importantes du d\xe9veloppement de Wave.\nNous pr\xe9voyons de fournir des documents officiels et des tutoriels complets afin que m\xeame les utilisateurs d\xe9butants puissent facilement apprendre et utiliser Wave dans leur pratique professionnelle."}),"\n",(0,a.jsx)(n.p,{children:"Du point de vue de la plateforme, l'objectif est d'offrir des performances et une exp\xe9rience de d\xe9veloppement coh\xe9rentes sur les principaux syst\xe8mes d'exploitation, y compris Windows, macOS et Linux."}),"\n",(0,a.jsx)(n.p,{children:"Enfin, Wave est un projet qui se d\xe9veloppe gr\xe2ce \xe0 la collaboration avec la communaut\xe9 open source.\nNous encouragerons activement les contributions et la participation, et \xe0 travers un processus de d\xe9veloppement ouvert, nous construirons ensemble la direction et le degr\xe9 d'ach\xe8vement de Wave."})]})}function c(e={}){const{wrapper:n}={...(0,i.R)(),...e.components};return n?(0,a.jsx)(n,{...e,children:(0,a.jsx)(d,{...e})}):d(e)}},8453:(e,n,t)=>{t.d(n,{R:()=>r,x:()=>o});var s=t(6540);const a={},i=s.createContext(a);function r(e){const n=s.useContext(i);return s.useMemo(function(){return"function"==typeof e?e(n):{...n,...e}},[n,e])}function o(e){let n;return n=e.disableParentContext?"function"==typeof e.components?e.components(a):e.components||a:r(e.components),s.createElement(i.Provider,{value:n},e.children)}}}]);